#!/usr/bin/env node
/**
 * Refresh generated documentation content, then build the public site.
 *
 * This wraps the same local sync paths used during product doc refreshes and
 * ensures /llms.txt and /llms-full.txt are regenerated by the final build.
 */

import { execFileSync } from 'node:child_process';

const syncArgs = process.argv.slice(2);
const targetArgs = syncArgs.length > 0 ? syncArgs : ['--examples'];

run(process.execPath, ['scripts/sync-local-docs.mjs', ...targetArgs]);
run('npm', ['run', 'build']);

function run(command, args) {
  console.log(`Running: ${command} ${args.join(' ')}`);
  execFileSync(command, args, { stdio: 'inherit' });
}
